let questions = [];
let currentQuestion = null;

let correctCount = 0;
let wrongCount = 0;

let wrongAnswersLog = loadWrongLog();

// Session állapot
let sessionQuestions = [];
let sessionIndex = 0;
let sessionResults = {};

// Hibás válaszok log — localStorage-ból töltődik be induláskor

// --- Hibás válaszok log (localStorage) ---
function loadWrongLog() {
    try {
        return JSON.parse(localStorage.getItem('kviz_wrong_log') || '[]');
    } catch {
        return [];
    }
}

function saveWrongLog() {
    localStorage.setItem('kviz_wrong_log', JSON.stringify(wrongAnswersLog));
}

// --- Ismert kérdések kezelése (localStorage) ---
function loadKnown() {
    try {
        return new Set(JSON.parse(localStorage.getItem('kviz_known') || '[]'));
    } catch {
        return new Set();
    }
}

function saveKnown(known) {
    localStorage.setItem('kviz_known', JSON.stringify([...known]));
}

function updatePoolCounter() {
    const known = loadKnown();
    document.getElementById("pool-count").innerText = questions.length - known.size;
}

function markAsKnown() {
    const known = loadKnown();
    known.add(currentQuestion.id);
    saveKnown(known);
    updatePoolCounter();

    sessionIndex++;
    updateProgressBar();

    const card = document.getElementById("quiz-card");
    card.classList.add("fade-out");
    setTimeout(() => {
        showQuestion();
        card.classList.remove("fade-out");
        card.classList.add("fade-in");
        setTimeout(() => card.classList.remove("fade-in"), 300);
    }, 300);
}

function resetPool() {
    if (!confirm("Resetezi baza de date completă? Toate întrebările vor fi readăugate în pool și istoricul erorilor va fi șters.")) return;
    localStorage.removeItem('kviz_known');
    localStorage.removeItem('kviz_history');
    localStorage.removeItem('kviz_wrong_log');
    wrongAnswersLog = [];
    updatePoolCounter();
    startSession();
}

// --- Előzmény kezelés (localStorage) ---
function loadHistory() {
    try {
        return JSON.parse(localStorage.getItem('kviz_history') || '{}');
    } catch {
        return {};
    }
}

function saveHistory(history) {
    localStorage.setItem('kviz_history', JSON.stringify(history));
}

// --- Súlyozott mintavétel ismétlés nélkül (Efraimidis-Spirakis) ---
function selectSessionQuestions() {
    const history = loadHistory();
    const known = loadKnown();
    const available = questions.filter(q => !known.has(q.id));
    const scored = available.map(q => {
        const h = history[q.id] || { errors: 0, consecutive: 0 };
        const graduated = h.consecutive >= 2;
        const weight = (!graduated && h.errors > 0) ? 1 + h.errors * 3 : 1;
        return { q, score: Math.random() ** (1 / weight) };
    });
    scored.sort((a, b) => b.score - a.score);
    return scored.slice(0, 50).map(x => x.q);
}

// --- Session indítása ---
function startSession() {
    correctCount = 0;
    wrongCount = 0;
    sessionQuestions = selectSessionQuestions();
    sessionIndex = 0;
    sessionResults = {};

    // Kártya struktúra helyreállítása (ha az előző session végeredménye látszott)
    const card = document.getElementById("quiz-card");
    if (!document.getElementById("question")) {
        card.innerHTML = `<div id="question" class="question"></div><div id="answers" class="answers"></div>`;
    }

    document.getElementById("correct").innerText = 0;
    document.getElementById("wrong").innerText = 0;
    updateProgressBar();
    updatePoolCounter();
    showQuestion();
}

// --- Session vége: előzmény mentése + eredmény megjelenítése ---
function endSession() {
    const history = loadHistory();
    sessionQuestions.forEach(q => {
        const result = sessionResults[q.id];
        if (!history[q.id]) history[q.id] = { errors: 0, consecutive: 0 };
        if (result === 'wrong') {
            history[q.id].errors++;
            history[q.id].consecutive = 0;
        } else if (result === 'correct' && history[q.id].errors > 0) {
            history[q.id].consecutive++;
            if (history[q.id].consecutive >= 2) {
                history[q.id].errors = 0;
                history[q.id].consecutive = 0;
            }
        }
    });
    saveHistory(history);

    const sessionTotal = sessionQuestions.length;
    const pct = sessionTotal > 0 ? Math.round(correctCount / sessionTotal * 100) : 0;
    const allHistory = history;
    const practicing = Object.keys(allHistory).filter(
        id => allHistory[id].errors > 0 && allHistory[id].consecutive < 2
    ).length;
    const statsText = practicing === 0 ? `Ai reluat toate întrebările greșite anterior!` : ``;

    const card = document.getElementById("quiz-card");
    card.innerHTML = `
        <div style="text-align:center; padding:20px 0;">
            <div style="font-size:56px; font-weight:700; color:${pct >= 70 ? '#22c55e' : '#ef4444'};">${pct}%</div>
            <div style="font-size:20px; color:#555; margin-top:8px;">${correctCount} / ${sessionTotal} răspunsuri corecte</div>
            <div style="margin-top:20px; color:#777; font-size:15px;">${statsText}</div>
            <button onclick="startSession()" style="margin-top:30px; padding:14px 40px; font-size:18px; background:#4f46e5; color:white; border:none; border-radius:12px; cursor:pointer; font-family:inherit; font-weight:600;">
                Începe sesiune nouă
            </button>
        </div>
    `;
}

// Indítás
questions = parseCSV(csvData);
startSession();

// --- Nézetek közötti váltás ---
function switchView(viewName) {
    const quizView = document.getElementById("quiz-view");
    const statsView = document.getElementById("stats-view");
    const btnQuiz = document.getElementById("nav-quiz");
    const btnStats = document.getElementById("nav-stats");

    if (viewName === 'quiz') {
        quizView.classList.remove("hidden");
        statsView.classList.add("hidden");
        btnQuiz.classList.add("active");
        btnStats.classList.remove("active");
    } else {
        quizView.classList.add("hidden");
        statsView.classList.remove("hidden");
        btnQuiz.classList.remove("active");
        btnStats.classList.add("active");
        renderWrongAnswersTable(); // Frissítjük a táblázatot, amikor rákattintanak
    }
}

// --- Táblázat legenerálása a hibás válaszokból ---
function renderWrongAnswersTable() {
    const tbody = document.getElementById("wrong-answers-body");
    tbody.innerHTML = "";

    if (wrongAnswersLog.length === 0) {
        tbody.innerHTML = `<tr><td colspan="3" style="text-align: center; color: #666; padding: 20px;">Nu ai niciun răspuns greșit. Continuă așa!</td></tr>`;
        return;
    }

    wrongAnswersLog.forEach(item => {
        const tr = document.createElement("tr");

        const tdQuestion = document.createElement("td");
        tdQuestion.innerText = item.question;

        const tdCorrect = document.createElement("td");
        tdCorrect.innerText = item.correctText;
        tdCorrect.classList.add("table-correct-cell");

        const tdChosen = document.createElement("td");
        tdChosen.innerText = item.chosenText;
        tdChosen.classList.add("table-wrong-cell"); // Piros kiemelést kap

        tr.appendChild(tdQuestion);
        tr.appendChild(tdCorrect);
        tr.appendChild(tdChosen);
        tbody.appendChild(tr);
    });
}

// --- UNIVERZÁLIS PARSER ---
function parseCSV(csv) {
    const cleanCsv = csv.replace(/\r/g, "").trim();
    const rawLines = cleanCsv.split("\n");
    if (rawLines.length === 0) return [];

    const firstLine = rawLines[0];
    let separator = ",";
    if (firstLine.includes("\t")) {
        separator = "\t";
    } else if (firstLine.includes(";")) {
        separator = ";";
    }

    const lines = [];
    let currentLine = [];
    let currentCell = "";
    let insideQuotes = false;

    for (let i = 0; i < cleanCsv.length; i++) {
        const char = cleanCsv[i];
        if (char === '"') {
            insideQuotes = !insideQuotes;
        } else if (char === separator && !insideQuotes) {
            currentLine.push(currentCell.trim());
            currentCell = "";
        } else if (char === '\n' && !insideQuotes) {
            currentLine.push(currentCell.trim());
            lines.push(currentLine);
            currentLine = [];
            currentCell = "";
        } else {
            currentCell += char;
        }
    }
    if (currentCell || currentLine.length > 0) {
        currentLine.push(currentCell.trim());
        lines.push(currentLine);
    }

    const headers = lines[0];

    return lines.slice(1).map(cols => {
        let obj = {};
        headers.forEach((h, i) => {
            let value = cols[i] ? cols[i].trim() : "";
            if (value.startsWith('"') && value.endsWith('"')) {
                value = value.slice(1, -1).trim();
            }
            obj[h.trim()] = value;
        });
        obj.errors = 0;
        obj.corrects = 0;
        return obj;
    });
}

// --- Kérdés megjelenítése ---
function showQuestion() {
    if (sessionIndex >= sessionQuestions.length) {
        endSession();
        return;
    }

    currentQuestion = sessionQuestions[sessionIndex];

    const questionEl = document.getElementById("question");
    questionEl.innerHTML = `<span style="font-size:13px; color:#999; font-weight:400; display:block; margin-bottom:8px;">${sessionIndex + 1} / 50</span>`;
    questionEl.appendChild(document.createTextNode(currentQuestion.intrebare));

    const answersDiv = document.getElementById("answers");
    answersDiv.innerHTML = "";

    let validLetters = ["a", "b", "c", "d", "e", "f"].filter(letter => {
        return currentQuestion[letter] && currentQuestion[letter] !== "0";
    });

    for (let i = validLetters.length - 1; i > 0; i--) {
        const j = Math.floor(Math.random() * (i + 1));
        [validLetters[i], validLetters[j]] = [validLetters[j], validLetters[i]];
    }

    validLetters.forEach(letter => {
        const btn = document.createElement("button");
        btn.innerText = currentQuestion[letter];
        btn.dataset.letter = letter.toUpperCase();
        btn.onclick = (e) => checkAnswer(e.target, letter);
        answersDiv.appendChild(btn);
    });

    const knowBtn = document.createElement("button");
    knowBtn.className = "btn-know";
    knowBtn.innerText = "Nu mai arăta!";
    knowBtn.onclick = markAsKnown;
    answersDiv.appendChild(knowBtn);
}

// --- Válasz ellenőrzése ---
function checkAnswer(clickedButton, rawLetter) {
    const buttons = document.querySelectorAll("#answers button");
    buttons.forEach(btn => btn.style.pointerEvents = "none");

    const card = document.getElementById("quiz-card");
    const chosenLetter = clickedButton.dataset.letter;
    const correctLetter = (currentQuestion["Raspuns corect"] || currentQuestion["Raspuns"]).toUpperCase();

    if (chosenLetter === correctLetter) {
        correctCount++;
        sessionResults[currentQuestion.id] = 'correct';
        clickedButton.classList.add("btn-correct");
    } else {
        wrongCount++;
        sessionResults[currentQuestion.id] = 'wrong';
        clickedButton.classList.add("btn-wrong");

        // Megkeressünk a helyes válasz betűjelének kisbetűs megfelelőjét a szöveg kinyeréséhez
        const correctRawLetter = correctLetter.toLowerCase();

        // Elmentjük a hibás választ a logba a táblázat számára
        wrongAnswersLog.push({
            question: currentQuestion.intrebare,
            correctText: currentQuestion[correctRawLetter],
            chosenText: currentQuestion[rawLetter]
        });
        saveWrongLog();

        buttons.forEach(btn => {
            if (btn.dataset.letter === correctLetter) {
                btn.classList.add("btn-correct-highlight");
            }
        });
    }

    sessionIndex++;
    updateProgressBar();

    document.getElementById("correct").innerText = correctCount;
    document.getElementById("wrong").innerText = wrongCount;

    setTimeout(() => {
        card.classList.add("fade-out");

        setTimeout(() => {
            showQuestion();
            card.classList.remove("fade-out");
            card.classList.add("fade-in");
            setTimeout(() => card.classList.remove("fade-in"), 300);
        }, 300);
    }, 1500); 
}

// --- Progress bar (session haladás) ---
function updateProgressBar() {
    const bar = document.getElementById("progress-bar");
    const total = sessionQuestions.length || 50;
    bar.style.width = Math.round((sessionIndex / total) * 100) + "%";
}
